     1→import {digest} from "@chainsafe/as-sha256";
     2→import {ChainForkConfig} from "@lodestar/config";
     3→import {
     4→  DATA_COLUMN_SIDECAR_SUBNET_COUNT,
     5→  ForkName,
     6→  NUMBER_OF_COLUMNS,
     7→  NUMBER_OF_CUSTODY_GROUPS,
     8→} from "@lodestar/params";
     9→import {signedBlockToSignedHeader} from "@lodestar/state-transition";
    10→import {ColumnIndex, CustodyIndex, SignedBeaconBlockHeader, deneb, fulu} from "@lodestar/types";
    11→import {ssz} from "@lodestar/types";
    12→import {bytesToBigInt} from "@lodestar/utils";
    13→import {
    14→  BlockInputDataColumns,
    15→  BlockSource,
    16→  DataColumnsCacheMap,
    17→  DataColumnsSource,
    18→  getBlockInput,
    19→  getBlockInputDataColumns,
    20→} from "../chain/blocks/types.js";
    21→import {ChainEvent, ChainEventEmitter} from "../chain/emitter.js";
    22→import {BlockInputCacheType} from "../chain/seenCache/seenGossipBlockInput.js";
    23→import {IExecutionEngine} from "../execution/engine/interface.js";
    24→import {Metrics} from "../metrics/metrics.js";
    25→import {NodeId} from "../network/subnets/index.js";
    26→import {
    27→  computeKzgCommitmentsInclusionProof,
    28→  kzgCommitmentToVersionedHash,
    29→  recoverDataColumnSidecars as recover,
    30→} from "./blobs.js";
    31→import {IClock} from "./clock.js";
    32→import {kzg} from "./kzg.js";
    33→
    34→export enum RecoverResult {
    35→  // the recover is not attempted because we have less than `NUMBER_OF_COLUMNS / 2` columns
    36→  NotAttemptedLessThanHalf = "not_attempted_less_than_half",
    37→  // the recover is not attempted because it has full data columns
    38→  NotAttemptedFull = "not_attempted_full",
    39→  // the recover is a success and it helps resolve availability
    40→  SuccessResolved = "success_resolved",
    41→  // the recover is a success but it's late, availability is already resolved by either gossip or getBlobsV2
    42→  SuccessLate = "success_late",
    43→  // the recover failed
    44→  Failed = "failed",
    45→}
    46→
    47→export type CustodyConfigOpts = {
    48→  nodeId: NodeId;
    49→  config: ChainForkConfig;
    50→  initialCustodyGroupCount?: number;
    51→};
    52→
    53→export class CustodyConfig {
    54→  /**
    55→   * The number of custody groups the node should subscribe to
    56→   */
    57→  targetCustodyGroupCount: number;
    58→
    59→  /**
    60→   * The custody columns the node should subscribe to
    61→   */
    62→  custodyColumns: ColumnIndex[];
    63→
    64→  /**
    65→   * Custody columns map which column maps to which index in the array of columns custodied
    66→   * with zero representing it is not custodied
    67→   */
    68→  custodyColumnsIndex: Uint8Array;
    69→
    70→  /**
    71→   * The number of custody groups the node will sample
    72→   */
    73→  sampledGroupCount: number;
    74→
    75→  /**
    76→   * Custody groups sampled by the node as part of custody sampling
    77→   */
    78→  sampleGroups: CustodyIndex[];
    79→
    80→  /**
    81→   * Data columns sampled by the node as part of custody sampling
    82→   * https://github.com/ethereum/consensus-specs/blob/v1.6.0-alpha.4/specs/fulu/das-core.md#custody-sampling
    83→   *
    84→   * TODO: Consider race conditions if this updates during sync/backfill
    85→   */
    86→  sampledColumns: ColumnIndex[];
    87→
    88→  /**
    89→   * Subnets sampled by the node as part of custody sampling
    90→   */
    91→  sampledSubnets: number[];
    92→
    93→  private config: ChainForkConfig;
    94→  private nodeId: NodeId;
    95→
    96→  constructor(opts: CustodyConfigOpts) {
    97→    this.config = opts.config;
    98→    this.nodeId = opts.nodeId;
    99→    this.targetCustodyGroupCount = opts.initialCustodyGroupCount ?? this.config.CUSTODY_REQUIREMENT;
   100→    this.custodyColumns = getDataColumns(this.nodeId, this.targetCustodyGroupCount);
   101→    this.custodyColumnsIndex = this.getCustodyColumnsIndex(this.custodyColumns);
   102→    this.sampledGroupCount = Math.max(this.targetCustodyGroupCount, this.config.SAMPLES_PER_SLOT);
   103→    this.sampleGroups = getCustodyGroups(this.nodeId, this.sampledGroupCount);
   104→    this.sampledColumns = getDataColumns(this.nodeId, this.sampledGroupCount);
   105→    this.sampledSubnets = this.sampledColumns.map(computeSubnetForDataColumn);
   106→  }
   107→
   108→  updateTargetCustodyGroupCount(targetCustodyGroupCount: number) {
   109→    this.targetCustodyGroupCount = targetCustodyGroupCount;
   110→    this.custodyColumns = getDataColumns(this.nodeId, this.targetCustodyGroupCount);
   111→    this.custodyColumnsIndex = this.getCustodyColumnsIndex(this.custodyColumns);
   112→    // TODO: Porting this over to match current behavior, but I think this incorrectly mixes units:
   113→    // SAMPLES_PER_SLOT is in columns, and CUSTODY_GROUP_COUNT is in groups
   114→    this.sampledGroupCount = Math.max(this.targetCustodyGroupCount, this.config.SAMPLES_PER_SLOT);
   115→    this.sampleGroups = getCustodyGroups(this.nodeId, this.sampledGroupCount);
   116→    this.sampledColumns = getDataColumns(this.nodeId, this.sampledGroupCount);
   117→    this.sampledSubnets = this.sampledColumns.map(computeSubnetForDataColumn);
   118→  }
   119→
   120→  private getCustodyColumnsIndex(custodyColumns: ColumnIndex[]): Uint8Array {
   121→    // custody columns map which column maps to which index in the array of columns custodied
   122→    // with zero representing it is not custodied
   123→    const custodyColumnsIndex = new Uint8Array(NUMBER_OF_COLUMNS);
   124→    let custodyAtIndex = 1;
   125→    for (const columnIndex of custodyColumns) {
   126→      custodyColumnsIndex[columnIndex] = custodyAtIndex;
   127→      custodyAtIndex++;
   128→    }
   129→    return custodyColumnsIndex;
   130→  }
   131→}
   132→
   133→function computeSubnetForDataColumn(columnIndex: ColumnIndex): number {
   134→  return columnIndex % DATA_COLUMN_SIDECAR_SUBNET_COUNT;
   135→}
   136→
   137→/**
   138→ * Calculate the number of custody groups the node should subscribe to based on the node's effective balance
   139→ *
   140→ * SPEC FUNCTION
   141→ * https://github.com/ethereum/consensus-specs/blob/v1.6.0-alpha.3/specs/fulu/validator.md#validator-custody
   142→ */
   143→export function getValidatorsCustodyRequirement(config: ChainForkConfig, effectiveBalances: number[]): number {
   144→  if (effectiveBalances.length === 0) {
   145→    return config.CUSTODY_REQUIREMENT;
   146→  }
   147→
   148→  const totalNodeEffectiveBalance = effectiveBalances.reduce((total, effectiveBalance) => {
   149→    return total + effectiveBalance;
   150→  }, 0);
   151→
   152→  // Must custody one group for every BALANCE_PER_ADDITIONAL_CUSTODY_GROUP of effective balance
   153→  let validatorsCustodyRequirement = Math.floor(
   154→    totalNodeEffectiveBalance / config.BALANCE_PER_ADDITIONAL_CUSTODY_GROUP
   155→  );
   156→
   157→  // Any node with at least 1 validator must custody at least VALIDATOR_CUSTODY_REQUIREMENT
   158→  validatorsCustodyRequirement = Math.max(validatorsCustodyRequirement, config.VALIDATOR_CUSTODY_REQUIREMENT);
   159→
   160→  // Cannot custody more than NUMBER_OF_CUSTODY_GROUPS
   161→  validatorsCustodyRequirement = Math.min(validatorsCustodyRequirement, NUMBER_OF_CUSTODY_GROUPS);
   162→
   163→  return validatorsCustodyRequirement;
   164→}
   165→
   166→/**
   167→ * Converts a custody group to an array of column indices.  Should be 1-1 as long there are 128
   168→ * columns and 128 custody groups.
   169→ *
   170→ * SPEC FUNCTION
   171→ * https://github.com/ethereum/consensus-specs/blob/v1.6.0-alpha.4/specs/fulu/das-core.md#compute_columns_for_custody_group
   172→ */
   173→export function computeColumnsForCustodyGroup(custodyIndex: CustodyIndex): ColumnIndex[] {
   174→  if (custodyIndex > NUMBER_OF_CUSTODY_GROUPS) {
   175→    throw Error(`Invalid custody index ${custodyIndex} > ${NUMBER_OF_CUSTODY_GROUPS}`);
   176→  }
   177→  const columnsPerCustodyGroup = Number(NUMBER_OF_COLUMNS / NUMBER_OF_CUSTODY_GROUPS);
   178→  const columnIndexes = [];
   179→  for (let i = 0; i < columnsPerCustodyGroup; i++) {
   180→    columnIndexes.push(NUMBER_OF_CUSTODY_GROUPS * i + custodyIndex);
   181→  }
   182→  columnIndexes.sort((a, b) => a - b);
   183→  return columnIndexes;
   184→}
   185→
   186→/**
   187→ * Converts nodeId and a the number of custody groups to an array of custody indices. Indexes must be
   188→ * further converted to column indices
   189→ *
   190→ * SPEC FUNCTION
   191→ * https://github.com/ethereum/consensus-specs/blob/v1.6.0-alpha.4/specs/fulu/das-core.md#get_custody_groups
   192→ */
   193→export function getCustodyGroups(nodeId: NodeId, custodyGroupCount: number): CustodyIndex[] {
   194→  if (custodyGroupCount > NUMBER_OF_CUSTODY_GROUPS) {
   195→    throw Error(`Invalid custody group count ${custodyGroupCount} > ${NUMBER_OF_CUSTODY_GROUPS}`);
   196→  }
   197→
   198→  // Skip computation if all groups are custodied
   199→  if (custodyGroupCount === NUMBER_OF_CUSTODY_GROUPS) {
   200→    return Array.from({length: NUMBER_OF_CUSTODY_GROUPS}, (_, i) => i);
   201→  }
   202→
   203→  const custodyGroups: CustodyIndex[] = [];
   204→  // nodeId is in bigendian and all computes are in little endian
   205→  let currentId = bytesToBigInt(nodeId, "be");
   206→  while (custodyGroups.length < custodyGroupCount) {
   207→    // could be optimized
   208→    const currentIdBytes = ssz.UintBn256.serialize(currentId);
   209→    const custodyGroup = Number(
   210→      ssz.UintBn64.deserialize(digest(currentIdBytes).slice(0, 8)) % BigInt(NUMBER_OF_CUSTODY_GROUPS)
   211→    );
   212→
   213→    if (!custodyGroups.includes(custodyGroup)) {
   214→      custodyGroups.push(custodyGroup);
   215→    }
   216→
   217→    const willOverflow = currentIdBytes.reduce((acc, elem) => acc && elem === 0xff, true);
   218→    if (willOverflow) {
   219→      currentId = BigInt(0);
   220→    } else {
   221→      currentId++;
   222→    }
   223→  }
   224→
   225→  custodyGroups.sort((a, b) => a - b);
   226→  return custodyGroups;
   227→}
   228→
   229→export function getDataColumns(nodeId: NodeId, custodyGroupCount: number): ColumnIndex[] {
   230→  return getCustodyGroups(nodeId, custodyGroupCount)
   231→    .flatMap(computeColumnsForCustodyGroup)
   232→    .sort((a, b) => a - b);
   233→}
   234→
   235→/**
   236→ * Computes the cells for each blob and combines them with cell proofs.
   237→ * Similar to the computeMatrix function described below.
   238→ *
   239→ * SPEC FUNCTION (note: spec currently computes proofs, but we already have them)
   240→ * https://github.com/ethereum/consensus-specs/blob/v1.6.0-alpha.4/specs/fulu/das-core.md#compute_matrix
   241→ */
   242→export function getCellsAndProofs(blobBundles: fulu.BlobAndProofV2[]): {cells: Uint8Array[]; proofs: Uint8Array[]}[] {
   243→  return blobBundles.map(({blob, proofs}) => {
   244→    const cells = kzg.computeCells(blob);
   245→    return {cells, proofs};
   246→  });
   247→}
   248→
   249→/**
   250→ * Given a signed block header and the commitments, inclusion proof, cells/proofs associated with
   251→ * each blob in the block, assemble the sidecars which can be distributed to peers.
   252→ *
   253→ * SPEC FUNCTION
   254→ * https://github.com/ethereum/consensus-specs/blob/v1.6.0-alpha.4/specs/fulu/validator.md#get_data_column_sidecars
   255→ */
   256→export function getDataColumnSidecars(
   257→  signedBlockHeader: SignedBeaconBlockHeader,
   258→  kzgCommitments: deneb.KZGCommitment[],
   259→  kzgCommitmentsInclusionProof: fulu.KzgCommitmentsInclusionProof,
   260→  cellsAndKzgProofs: {cells: Uint8Array[]; proofs: Uint8Array[]}[]
   261→): fulu.DataColumnSidecars {
   262→  if (cellsAndKzgProofs.length !== kzgCommitments.length) {
   263→    throw Error("Invalid cellsAndKzgProofs length for getDataColumnSidecars");
   264→  }
   265→
   266→  const sidecars: fulu.DataColumnSidecars = [];
   267→  for (let columnIndex = 0; columnIndex < NUMBER_OF_COLUMNS; columnIndex++) {
   268→    const columnCells = [];
   269→    const columnProofs = [];
   270→    for (const {cells, proofs} of cellsAndKzgProofs) {
   271→      columnCells.push(cells[columnIndex]);
   272→      columnProofs.push(proofs[columnIndex]);
   273→    }
   274→    sidecars.push({
   275→      index: columnIndex,
   276→      column: columnCells,
   277→      kzgCommitments,
   278→      kzgProofs: columnProofs,
   279→      signedBlockHeader,
   280→      kzgCommitmentsInclusionProof,
   281→    });
   282→  }
   283→  return sidecars;
   284→}
   285→
   286→/**
   287→ * Given a signed block and the cells/proofs associated with each blob in the
   288→ * block, assemble the sidecars which can be distributed to peers.
   289→ *
   290→ * SPEC FUNCTION
   291→ * https://github.com/ethereum/consensus-specs/blob/v1.6.0-alpha.4/specs/fulu/validator.md#get_data_column_sidecars_from_block
   292→ */
   293→export function getDataColumnSidecarsFromBlock(
   294→  config: ChainForkConfig,
   295→  signedBlock: fulu.SignedBeaconBlock,
   296→  cellsAndKzgProofs: {cells: Uint8Array[]; proofs: Uint8Array[]}[]
   297→): fulu.DataColumnSidecars {
   298→  const blobKzgCommitments = signedBlock.message.body.blobKzgCommitments;
   299→  const fork = config.getForkName(signedBlock.message.slot);
   300→  const signedBlockHeader = signedBlockToSignedHeader(config, signedBlock);
   301→
   302→  const kzgCommitmentsInclusionProof = computeKzgCommitmentsInclusionProof(fork, signedBlock.message.body);
   303→
   304→  return getDataColumnSidecars(signedBlockHeader, blobKzgCommitments, kzgCommitmentsInclusionProof, cellsAndKzgProofs);
   305→}
   306→
   307→/**
   308→ * Given a DataColumnSidecar and the cells/proofs associated with each blob corresponding
   309→ * to the commitments it contains, assemble all sidecars for distribution to peers.
   310→ *
   311→ * SPEC FUNCTION
   312→ * https://github.com/ethereum/consensus-specs/blob/v1.6.0-alpha.4/specs/fulu/validator.md#get_data_column_sidecars_from_column_sidecar
   313→ */
   314→export function getDataColumnSidecarsFromColumnSidecar(
   315→  sidecar: fulu.DataColumnSidecar,
   316→  cellsAndKzgProofs: {cells: Uint8Array[]; proofs: Uint8Array[]}[]
   317→): fulu.DataColumnSidecars {
   318→  return getDataColumnSidecars(
   319→    sidecar.signedBlockHeader,
   320→    sidecar.kzgCommitments,
   321→    sidecar.kzgCommitmentsInclusionProof,
   322→    cellsAndKzgProofs
   323→  );
   324→}
   325→
   326→/**
   327→ * If we receive more than half of NUMBER_OF_COLUMNS (64) we should recover all remaining columns
   328→ */
   329→export async function recoverDataColumnSidecars(
   330→  dataColumnCache: DataColumnsCacheMap,
   331→  clock: IClock,
   332→  metrics: Metrics | null
   333→): Promise<RecoverResult> {
   334→  const columnCount = dataColumnCache.size;
   335→  if (columnCount >= NUMBER_OF_COLUMNS) {
   336→    // We have all columns
   337→    return RecoverResult.NotAttemptedFull;
   338→  }
   339→
   340→  if (columnCount < NUMBER_OF_COLUMNS / 2) {
   341→    // We don't have enough columns to recover
   342→    return RecoverResult.NotAttemptedLessThanHalf;
   343→  }
   344→
   345→  const partialColumns = dataColumnCache.size;
   346→  metrics?.recoverDataColumnSidecars.custodyBeforeReconstruction.set(partialColumns);
   347→  const partialSidecars = new Map<number, fulu.DataColumnSidecar>();
   348→  for (const [columnIndex, {dataColumn}] of dataColumnCache.entries()) {
   349→    // the more columns we put, the slower the recover
   350→    if (partialSidecars.size >= NUMBER_OF_COLUMNS / 2) {
   351→      break;
   352→    }
   353→    partialSidecars.set(columnIndex, dataColumn);
   354→  }
   355→
   356→  const timer = metrics?.peerDas.dataColumnsReconstructionTime.startTimer();
   357→  // if this function throws, we catch at the consumer side
   358→  const fullSidecars = await recover(partialSidecars);
   359→  timer?.();
   360→  if (fullSidecars == null) {
   361→    return RecoverResult.Failed;
   362→  }
   363→
   364→  const firstDataColumn = dataColumnCache.values().next().value?.dataColumn;
   365→  if (firstDataColumn == null) {
   366→    // should not happen because we checked the size of the cache before this
   367→    throw new Error("No data column found in cache to recover from");
   368→  }
   369→
   370→  const slot = firstDataColumn.signedBlockHeader.message.slot;
   371→  const secFromSlot = clock.secFromSlot(slot);
   372→  metrics?.recoverDataColumnSidecars.elapsedTimeTillReconstructed.observe(secFromSlot);
   373→
   374→  if (dataColumnCache.size === NUMBER_OF_COLUMNS) {
   375→    // either gossip or getBlobsV2 resolved availability while we were recovering
   376→    return RecoverResult.SuccessLate;
   377→  }
   378→
   379→  // We successfully recovered the data columns, update the cache
   380→  for (let columnIndex = 0; columnIndex < NUMBER_OF_COLUMNS; columnIndex++) {
   381→    if (dataColumnCache.has(columnIndex)) {
   382→      // We already have this column
   383→      continue;
   384→    }
   385→
   386→    const sidecar = fullSidecars[columnIndex];
   387→    if (sidecar === undefined) {
   388→      throw new Error(`full sidecars is undefined at index ${columnIndex}`);
   389→    }
   390→    dataColumnCache.set(columnIndex, {dataColumn: sidecar, dataColumnBytes: null});
   391→    metrics?.peerDas.reconstructedColumns.inc(NUMBER_OF_COLUMNS - partialColumns);
   392→  }
   393→
   394→  return RecoverResult.SuccessResolved;
   395→}
   396→
   397→export function hasSampledDataColumns(custodyConfig: CustodyConfig, dataColumnCache: DataColumnsCacheMap): boolean {
   398→  return (
   399→    dataColumnCache.size >= custodyConfig.sampledColumns.length &&
   400→    custodyConfig.sampledColumns.reduce((acc, columnIndex) => acc && dataColumnCache.has(columnIndex), true)
   401→  );
   402→}
   403→
   404→export async function getDataColumnsFromExecution(
   405→  config: ChainForkConfig,
   406→  custodyConfig: CustodyConfig,
   407→  executionEngine: IExecutionEngine,
   408→  emitter: ChainEventEmitter,
   409→  blockCache: BlockInputCacheType,
   410→  metrics: Metrics | null
   411→): Promise<boolean> {
   412→  if (blockCache.fork !== ForkName.fulu) {
   413→    return false;
   414→  }
   415→
   416→  if (!blockCache.cachedData) {
   417→    // this condition should never get hit... just a sanity check
   418→    throw new Error("invalid blockCache");
   419→  }
   420→
   421→  if (blockCache.cachedData.fork !== ForkName.fulu) {
   422→    return false;
   423→  }
   424→
   425→  // If already have all columns, exit
   426→  if (hasSampledDataColumns(custodyConfig, blockCache.cachedData.dataColumnsCache)) {
   427→    return true;
   428→  }
   429→
   430→  let commitments: undefined | Uint8Array[];
   431→  if (blockCache.block) {
   432→    const block = blockCache.block as fulu.SignedBeaconBlock;
   433→    commitments = block.message.body.blobKzgCommitments;
   434→  } else {
   435→    const firstSidecar = blockCache.cachedData.dataColumnsCache.values().next().value;
   436→    commitments = firstSidecar?.dataColumn.kzgCommitments;
   437→  }
   438→
   439→  if (!commitments) {
   440→    throw new Error("blockInputCache missing both block and cachedData");
   441→  }
   442→
   443→  // Return if block has no blobs
   444→  if (commitments.length === 0) {
   445→    return true;
   446→  }
   447→
   448→  // Process KZG commitments into versioned hashes
   449→  const versionedHashes: Uint8Array[] = commitments.map(kzgCommitmentToVersionedHash);
   450→
   451→  // Get blobs from execution engine
   452→  metrics?.peerDas.getBlobsV2Requests.inc();
   453→  const timer = metrics?.peerDas.getBlobsV2RequestDuration.startTimer();
   454→  const blobs = await executionEngine.getBlobs(blockCache.fork, versionedHashes);
   455→  timer?.();
   456→
   457→  // Execution engine was unable to find one or more blobs
   458→  if (blobs === null) {
   459→    return false;
   460→  }
   461→  metrics?.peerDas.getBlobsV2Responses.inc();
   462→
   463→  // Return if we received all data columns while waiting for getBlobs
   464→  if (hasSampledDataColumns(custodyConfig, blockCache.cachedData.dataColumnsCache)) {
   465→    return true;
   466→  }
   467→
   468→  let dataColumnSidecars: fulu.DataColumnSidecars;
   469→  const cellsAndProofs = getCellsAndProofs(blobs);
   470→  if (blockCache.block) {
   471→    dataColumnSidecars = getDataColumnSidecarsFromBlock(
   472→      config,
   473→      blockCache.block as fulu.SignedBeaconBlock,
   474→      cellsAndProofs
   475→    );
   476→  } else {
   477→    const firstSidecar = blockCache.cachedData.dataColumnsCache.values().next().value;
   478→    if (!firstSidecar) {
   479→      throw new Error("blockInputCache missing both block and data column sidecar");
   480→    }
   481→    dataColumnSidecars = getDataColumnSidecarsFromColumnSidecar(firstSidecar.dataColumn, cellsAndProofs);
   482→  }
   483→
   484→  // Publish columns if and only if subscribed to them
   485→  const sampledColumns = custodyConfig.sampledColumns.map((columnIndex) => dataColumnSidecars[columnIndex]);
   486→
   487→  // for columns that we already seen, it will be ignored through `ignoreDuplicatePublishError` gossip option
   488→  emitter.emit(ChainEvent.publishDataColumns, sampledColumns);
   489→
   490→  for (const column of sampledColumns) {
   491→    blockCache.cachedData.dataColumnsCache.set(column.index, {dataColumn: column, dataColumnBytes: null});
   492→  }
   493→
   494→  const allDataColumns = getBlockInputDataColumns(blockCache.cachedData.dataColumnsCache, custodyConfig.sampledColumns);
   495→  // TODO: Add metrics
   496→  // metrics?.syncUnknownBlock.resolveAvailabilitySource.inc({source: BlockInputAvailabilitySource.GOSSIP});
   497→  const blockData: BlockInputDataColumns = {
   498→    fork: blockCache.cachedData.fork,
   499→    ...allDataColumns,
   500→    dataColumnsSource: DataColumnsSource.engine,
   501→  };
   502→  const partialColumns = blockCache.cachedData.dataColumnsCache.size;
   503→  blockCache.cachedData.resolveAvailability(blockData);
   504→  metrics?.dataColumns.bySource.inc({source: DataColumnsSource.engine}, NUMBER_OF_COLUMNS - partialColumns);
   505→
   506→  if (blockCache.block !== undefined) {
   507→    const blockInput = getBlockInput.availableData(config, blockCache.block, BlockSource.gossip, blockData);
   508→
   509→    blockCache.resolveBlockInput(blockInput);
   510→  }
   511→
   512→  return true;
   513→}
