   303→ * SPEC FUNCTION
   304→ * https://github.com/ethereum/consensus-specs/blob/v1.6.0-alpha.4/specs/fulu/p2p-interface.md#verify_data_column_sidecar_inclusion_proof
   305→ */
   306→export function verifyDataColumnSidecarInclusionProof(dataColumnSidecar: fulu.DataColumnSidecar): boolean {
   307→  return verifyMerkleBranch(
   308→    ssz.deneb.BlobKzgCommitments.hashTreeRoot(dataColumnSidecar.kzgCommitments),
   309→    dataColumnSidecar.kzgCommitmentsInclusionProof,
   310→    KZG_COMMITMENTS_INCLUSION_PROOF_DEPTH,
   311→    KZG_COMMITMENTS_SUBTREE_INDEX,
   312→    dataColumnSidecar.signedBlockHeader.message.bodyRoot
   313→  );
   314→}
   315→
