     4→import {ChainTarget} from "../range/utils/index.js";
     5→
     6→/** The type of peer relative to our current state */
     7→export enum PeerSyncType {
     8→  /** The peer is on our chain and is fully synced with respect to our chain */
     9→  FullySynced = "FullySynced",
    10→  /** The peer has a greater knowledge of the chain than us that warrants a full sync */
    11→  Advanced = "Advanced",
    12→  /** A peer is behind in the sync and not useful to us for downloading blocks */
    13→  Behind = "Behind",
