     1→import {ChainForkConfig} from "@lodestar/config";
     2→import {ForkName, ForkSeq} from "@lodestar/params";
     3→import {computeEpochAtSlot} from "@lodestar/state-transition";
     4→import {
     5→  ColumnIndex,
     6→  Epoch,
     7→  SignedBeaconBlock,
     8→  Slot,
     9→  WithOptionalBytes,
    10→  deneb,
    11→  fulu,
    12→  phase0,
    13→  ssz,
    14→} from "@lodestar/types";
    15→import {Logger} from "@lodestar/utils";
    16→import {
    17→  BlobsSource,
    18→  BlockInput,
    19→  BlockInputBlobs,
    20→  BlockInputDataColumns,
    21→  BlockInputType,
    22→  BlockSource,
    23→  CachedData,
    24→  CachedDataColumns,
    25→  DataColumnsSource,
    26→  getBlockInput,
    27→  getBlockInputDataColumns,
    28→} from "../../chain/blocks/types.js";
    29→import {getEmptyBlockInputCacheEntry} from "../../chain/seenCache/seenGossipBlockInput.js";
    30→import {Metrics} from "../../metrics/index.js";
    31→import {PeerIdStr} from "../../util/peerId.js";
    32→import {INetwork} from "../interface.js";
    33→import {PeerSyncMeta} from "../peers/peersData.js";
    34→import {PeerAction} from "../peers/score/interface.js";
    35→
    36→export type PartialDownload = null | {blocks: BlockInput[]; pendingDataColumns: number[]};
    37→
    38→/**
    39→ * Download blocks and blobs (prefulu) or data columns (fulu) by range.
    40→ * returns:
    41→ *  - array of blocks with blobs or data columns
    42→ *  - pendingDataColumns: null if all data columns are present, or array of column indexes that are missing. Also null for prefulu
    43→ */
    44→export async function beaconBlocksMaybeBlobsByRange(
    45→  config: ChainForkConfig,
    46→  network: INetwork,
    47→  peer: PeerSyncMeta,
    48→  request: phase0.BeaconBlocksByRangeRequest,
    49→  currentEpoch: Epoch,
    50→  partialDownload: PartialDownload,
    51→  metrics: Metrics | null,
    52→  logger?: Logger
    53→): Promise<{blocks: BlockInput[]; pendingDataColumns: null | number[]}> {
    54→  const {peerId, client: peerClient, custodyGroups: peerColumns, earliestAvailableSlot} = peer;
    55→  // Code below assumes the request is in the same epoch
    56→  // Range sync satisfies this condition, but double check here for sanity
    57→  const {startSlot, count} = request;
    58→  if (count < 1) {
    59→    throw Error(`Invalid count=${count} in BeaconBlocksByRangeRequest`);
    60→  }
    61→  const endSlot = startSlot + count - 1;
    62→
    63→  const startEpoch = computeEpochAtSlot(startSlot);
    64→  const endEpoch = computeEpochAtSlot(endSlot);
    65→  if (startEpoch !== endEpoch) {
    66→    throw Error(
    67→      `BeaconBlocksByRangeRequest must be in the same epoch startEpoch=${startEpoch} != endEpoch=${endEpoch}`
    68→    );
    69→  }
    70→
    71→  const forkSeq = config.getForkSeq(startSlot);
    72→
    73→  // Note: Assumes all blocks in the same epoch
    74→  if (forkSeq < ForkSeq.deneb) {
    75→    const beaconBlocks = await network.sendBeaconBlocksByRange(peerId, request);
    76→    if (beaconBlocks.length === 0) {
    77→      throw Error(
    78→        `peerId=${peerId} peerClient=${peerClient} returned no blocks for BeaconBlocksByRangeRequest ${JSON.stringify(request)}`
    79→      );
    80→    }
    81→
    82→    const blocks = beaconBlocks.map((block) => getBlockInput.preData(config, block.data, BlockSource.byRange));
    83→    return {blocks, pendingDataColumns: null};
    84→  }
    85→
    86→  // From Deneb
    87→  // Only request blobs if they are recent enough
    88→  if (startEpoch >= currentEpoch - config.MIN_EPOCHS_FOR_BLOB_SIDECARS_REQUESTS) {
    89→    if (forkSeq < ForkSeq.fulu) {
    90→      const [allBlocks, allBlobSidecars] = await Promise.all([
    91→        network.sendBeaconBlocksByRange(peerId, request),
    92→        network.sendBlobSidecarsByRange(peerId, request),
    93→      ]);
    94→
    95→      if (allBlocks.length === 0) {
    96→        throw Error(
    97→          `peerId=${peerId} peerClient=${peerClient} returns no blocks allBlobSidecars=${allBlobSidecars.length} for BeaconBlocksByRangeRequest ${JSON.stringify(request)}`
    98→        );
    99→      }
   100→
   101→      const blocks = matchBlockWithBlobs(
   102→        config,
   103→        allBlocks,
   104→        allBlobSidecars,
   105→        endSlot,
   106→        BlockSource.byRange,
   107→        BlobsSource.byRange
   108→      );
   109→      return {blocks, pendingDataColumns: null};
   110→    }
   111→
   112→    // From fulu, get columns
   113→    const sampledColumns = network.custodyConfig.sampledColumns;
   114→    const neededColumns = partialDownload ? partialDownload.pendingDataColumns : sampledColumns;
   115→
   116→    // This should never throw. Already checking for this in ChainPeerBalancer when selecting the peer
   117→    if ((earliestAvailableSlot ?? 0) > startSlot) {
   118→      throw new Error(
   119→        `earliestAvailableSlot=${earliestAvailableSlot} not respected for ByRange startSlot=${startSlot}`
   120→      );
   121→    }
   122→
   123→    // get match
   124→    const columns = peerColumns.reduce((acc, elem) => {
   125→      if (neededColumns.includes(elem)) {
   126→        acc.push(elem);
   127→      }
   128→      return acc;
   129→    }, [] as number[]);
   130→
   131→    if (columns.length === 0 && partialDownload !== null) {
   132→      // this peer has nothing to offer and should not have been selected for batch download
   133→      // throw error?
   134→      return partialDownload;
   135→    }
   136→
   137→    const pendingDataColumns = neededColumns.reduce((acc, elem) => {
   138→      if (!columns.includes(elem)) {
   139→        acc.push(elem);
   140→      }
   141→      return acc;
   142→    }, [] as number[]);
   143→
   144→    const dataColumnRequest = {...request, columns};
   145→    const [allBlocks, allDataColumnSidecars] = await Promise.all([
   146→      // TODO-das: investigate why partialDownload blocks is empty here
   147→      partialDownload && partialDownload.blocks.length > 0
   148→        ? partialDownload.blocks.map((blockInput) => ({data: blockInput.block}))
   149→        : network.sendBeaconBlocksByRange(peerId, request),
   150→      columns.length === 0 ? [] : network.sendDataColumnSidecarsByRange(peerId, dataColumnRequest),
   151→    ]);
   152→    logger?.debug("ByRange requests", {
   153→      beaconBlocksRequest: JSON.stringify(ssz.phase0.BeaconBlocksByRangeRequest.toJson(request)),
   154→      dataColumnRequest: JSON.stringify(ssz.fulu.DataColumnSidecarsByRangeRequest.toJson(dataColumnRequest)),
   155→      [`allBlocks(${allBlocks.length})`]: allBlocks.map((blk) => blk.data.message.slot).join(" "),
   156→      [`allDataColumnSidecars(${allDataColumnSidecars.length})`]: allDataColumnSidecars
   157→        .map((dCol) => `${dCol.signedBlockHeader.message.slot}:${dCol.index}`)
   158→        .join(" "),
   159→      peerColumns: peerColumns.join(" "),
   160→      peerId,
   161→      peerClient,
   162→      prevPartialDownload: !!partialDownload,
   163→    });
   164→
   165→    if (allBlocks.length === 0) {
   166→      throw Error(
   167→        `peerId=${peerId} peerClient=${peerClient} returns no blocks dataColumnSidecars=${allDataColumnSidecars.length} for BeaconBlocksByRangeRequest ${JSON.stringify(request)}`
   168→      );
   169→    }
   170→
   171→    const blocks = matchBlockWithDataColumns(
   172→      network,
   173→      peerId,
   174→      config,
   175→      sampledColumns,
   176→      columns,
   177→      allBlocks,
   178→      allDataColumnSidecars,
   179→      endSlot,
   180→      BlockSource.byRange,
   181→      DataColumnsSource.byRange,
   182→      partialDownload,
   183→      peerClient,
   184→      metrics,
   185→      logger
   186→    );
   187→
   188→    return {blocks, pendingDataColumns: pendingDataColumns.length > 0 ? pendingDataColumns : null};
   189→  }
   190→
   191→  logger?.verbose(
   192→    `Download range is out of ${config.MIN_EPOCHS_FOR_BLOB_SIDECARS_REQUESTS} epochs, skip Blobs and DataColumnSidecars download`,
   193→    {
   194→      startEpoch,
   195→      startSlot,
   196→      endSlot,
   197→      currentEpoch,
   198→    }
   199→  );
   200→
   201→  // Data is out of range, only request blocks
   202→  const blocks = await network.sendBeaconBlocksByRange(peerId, request);
   203→  if (blocks.length === 0) {
   204→    throw Error(
   205→      `peerId=${peerId} peerClient=${peerClient} returned no blocks for BeaconBlocksByRangeRequest ${JSON.stringify(request)}`
   206→    );
   207→  }
   208→  return {
   209→    blocks: blocks.map((block) => getBlockInput.outOfRangeData(config, block.data, BlockSource.byRange)),
   210→    // null means all data columns are present
   211→    pendingDataColumns: null,
   212→  };
   213→}
   214→
   215→// Assumes that the blobs are in the same sequence as blocks, doesn't require block to be sorted
   216→export function matchBlockWithBlobs(
   217→  config: ChainForkConfig,
   218→  allBlocks: WithOptionalBytes<SignedBeaconBlock>[],
   219→  allBlobSidecars: deneb.BlobSidecar[],
   220→  endSlot: Slot,
   221→  blockSource: BlockSource,
   222→  blobsSource: BlobsSource
   223→): BlockInput[] {
   224→  const blockInputs: BlockInput[] = [];
   225→  let blobSideCarIndex = 0;
   226→  let lastMatchedSlot = -1;
   227→
   228→  // Match blobSideCar with the block as some blocks would have no blobs and hence
   229→  // would be omitted from the response. If there are any inconsitencies in the
   230→  // response, the validations during import will reject the block and hence this
   231→  // entire segment.
   232→  //
   233→  // Assuming that the blocks and blobs will come in same sorted order
   234→  for (let i = 0; i < allBlocks.length; i++) {
   235→    const block = allBlocks[i];
   236→    if (config.getForkSeq(block.data.message.slot) < ForkSeq.deneb) {
   237→      blockInputs.push(getBlockInput.preData(config, block.data, blockSource));
   238→    } else {
   239→      const blobSidecars: deneb.BlobSidecar[] = [];
   240→
   241→      let blobSidecar: deneb.BlobSidecar;
   242→      while (
   243→        // biome-ignore lint/suspicious/noAssignInExpressions: <explanation>
   244→        (blobSidecar = allBlobSidecars[blobSideCarIndex])?.signedBlockHeader.message.slot === block.data.message.slot
   245→      ) {
   246→        blobSidecars.push(blobSidecar);
   247→        lastMatchedSlot = block.data.message.slot;
   248→        blobSideCarIndex++;
   249→      }
   250→
   251→      // Quick inspect how many blobSidecars was expected
   252→      const blobKzgCommitmentsLen = (block.data.message.body as deneb.BeaconBlockBody).blobKzgCommitments.length;
   253→      if (blobKzgCommitmentsLen !== blobSidecars.length) {
   254→        throw Error(
   255→          `Missing blobSidecars for blockSlot=${block.data.message.slot} with blobKzgCommitmentsLen=${blobKzgCommitmentsLen} blobSidecars=${blobSidecars.length}`
   256→        );
   257→      }
   258→
   259→      const blockData = {
   260→        fork: config.getForkName(block.data.message.slot),
   261→        blobs: blobSidecars,
   262→        blobsSource,
   263→      } as BlockInputBlobs;
   264→
   265→      blockInputs.push(getBlockInput.availableData(config, block.data, blockSource, blockData));
   266→    }
   267→  }
   268→
   269→  // If there are still unconsumed blobs this means that the response was inconsistent
   270→  // and matching was wrong and hence we should throw error
   271→  if (
   272→    allBlobSidecars[blobSideCarIndex] !== undefined &&
   273→    // If there are no blobs, the blobs request can give 1 block outside the requested range
   274→    allBlobSidecars[blobSideCarIndex].signedBlockHeader.message.slot <= endSlot
   275→  ) {
   276→    throw Error(
   277→      `Unmatched blobSidecars, blocks=${allBlocks.length}, blobs=${
   278→        allBlobSidecars.length
   279→      } lastMatchedSlot=${lastMatchedSlot}, pending blobSidecars slots=${allBlobSidecars
   280→        .slice(blobSideCarIndex)
   281→        .map((blb) => blb.signedBlockHeader.message.slot)
   282→        .join(" ")}`
   283→    );
   284→  }
   285→  return blockInputs;
   286→}
   287→
   288→export function matchBlockWithDataColumns(
   289→  network: INetwork,
   290→  peerId: PeerIdStr,
   291→  config: ChainForkConfig,
   292→  sampledColumns: ColumnIndex[],
   293→  requestedColumns: number[],
   294→  allBlocks: WithOptionalBytes<SignedBeaconBlock>[],
   295→  allDataColumnSidecars: fulu.DataColumnSidecar[],
   296→  endSlot: Slot,
   297→  blockSource: BlockSource,
   298→  dataColumnsSource: DataColumnsSource,
   299→  prevPartialDownload: null | PartialDownload,
   300→  peerClient: string,
   301→  metrics: Metrics | null,
   302→  logger?: Logger
   303→): BlockInput[] {
   304→  const blockInputs: BlockInput[] = [];
   305→  let dataColumnSideCarIndex = 0;
   306→  let lastMatchedSlot = -1;
   307→  const neededColumns = prevPartialDownload?.pendingDataColumns ?? sampledColumns;
   308→  const shouldHaveAllData = neededColumns.reduce((acc, elem) => acc && requestedColumns.includes(elem), true);
   309→
   310→  // Match dataColumnSideCar with the block as some blocks would have no dataColumns and hence
   311→  // would be omitted from the response. If there are any inconsitencies in the
   312→  // response, the validations during import will reject the block and hence this
   313→  // entire segment.
   314→  //
   315→  // Assuming that the blocks and blobs will come in same sorted order
   316→  for (let i = 0; i < allBlocks.length; i++) {
   317→    const block = allBlocks[i];
   318→
   319→    const forkSeq = config.getForkSeq(block.data.message.slot);
   320→    if (forkSeq < ForkSeq.fulu) {
   321→      throw Error(`Invalid block forkSeq=${forkSeq} < ForSeq.fulu for matchBlockWithDataColumns`);
   322→    }
   323→    const dataColumnSidecars: fulu.DataColumnSidecar[] = [];
   324→    while (allDataColumnSidecars[dataColumnSideCarIndex]?.signedBlockHeader.message.slot === block.data.message.slot) {
   325→      dataColumnSidecars.push(allDataColumnSidecars[dataColumnSideCarIndex]);
   326→      lastMatchedSlot = block.data.message.slot;
   327→      dataColumnSideCarIndex++;
   328→    }
   329→    metrics?.dataColumns.bySource.inc({source: DataColumnsSource.byRange}, dataColumnSidecars.length);
   330→
   331→    const blobKzgCommitmentsLen = (block.data.message.body as deneb.BeaconBlockBody).blobKzgCommitments.length;
   332→    logger?.debug("processing matchBlockWithDataColumns", {
   333→      blobKzgCommitmentsLen,
   334→      dataColumnSidecars: dataColumnSidecars.length,
   335→      shouldHaveAllData,
   336→      neededColumns: neededColumns.join(" "),
   337→      requestedColumns: requestedColumns.join(" "),
   338→      slot: block.data.message.slot,
   339→      dataColumnsSlots: dataColumnSidecars.map((dcm) => dcm.signedBlockHeader.message.slot).join(" "),
   340→      peerClient,
   341→    });
   342→    if (blobKzgCommitmentsLen === 0) {
   343→      if (dataColumnSidecars.length > 0) {
   344→        network.reportPeer(peerId, PeerAction.LowToleranceError, "Missing or mismatching dataColumnSidecars");
   345→        throw Error(
   346→          `Missing or mismatching dataColumnSidecars from peerId=${peerId} for blockSlot=${block.data.message.slot} with blobKzgCommitmentsLen=0 dataColumnSidecars=${dataColumnSidecars.length}>0`
   347→        );
   348→      }
   349→
   350→      const blockData = {
   351→        fork: config.getForkName(block.data.message.slot),
   352→        dataColumns: [],
   353→        dataColumnsBytes: [],
   354→        dataColumnsSource,
   355→      } as BlockInputDataColumns;
   356→      blockInputs.push(getBlockInput.availableData(config, block.data, blockSource, blockData));
   357→    } else {
   358→      // Quick inspect how many blobSidecars was expected
   359→      const dataColumnIndexes = dataColumnSidecars.map((dataColumnSidecar) => dataColumnSidecar.index);
   360→      const requestedColumnsPresent = requestedColumns.reduce(
   361→        (acc, columnIndex) => acc && dataColumnIndexes.includes(columnIndex),
   362→        true
   363→      );
   364→
   365→      logger?.debug("matchBlockWithDataColumns2", {
   366→        dataColumnIndexes: dataColumnIndexes.join(" "),
