     1→import {IForkChoice} from "@lodestar/fork-choice";
     2→import {computeEpochAtSlot, computeStartSlotAtEpoch} from "@lodestar/state-transition";
     3→import {Slot, Status} from "@lodestar/types";
     4→import {ChainTarget} from "../range/utils/index.js";
     5→
     6→/** The type of peer relative to our current state */
     7→export enum PeerSyncType {
     8→  /** The peer is on our chain and is fully synced with respect to our chain */
     9→  FullySynced = "FullySynced",
    10→  /** The peer has a greater knowledge of the chain than us that warrants a full sync */
    11→  Advanced = "Advanced",
    12→  /** A peer is behind in the sync and not useful to us for downloading blocks */
    13→  Behind = "Behind",
    14→}
    15→
    16→// Cache Object.keys iteration for faster loops in metrics
    17→export const peerSyncTypes = Object.keys(PeerSyncType) as PeerSyncType[];
    18→
    19→function withinRangeOf(value: number, target: number, range: number): boolean {
    20→  return value >= target - range && value <= target + range;
    21→}
    22→
    23→export function getPeerSyncType(
    24→  local: Status,
    25→  remote: Status,
    26→  forkChoice: IForkChoice,
    27→  slotImportTolerance: number
    28→): PeerSyncType {
    29→  // Aux vars: Inclusive boundaries of the range to consider a peer's head synced to ours.
    30→  const nearRangeStart = local.headSlot - slotImportTolerance;
    31→  const nearRangeEnd = local.headSlot + slotImportTolerance;
    32→
    33→  if (remote.finalizedEpoch < local.finalizedEpoch) {
    34→    // The node has a lower finalized epoch, their chain is not useful to us. There are two
    35→    // cases where a node can have a lower finalized epoch:
    36→    //
    37→    // ## The node is on the same chain
    38→    //
    39→    // If a node is on the same chain but has a lower finalized epoch, their head must be
    40→    // lower than ours. Therefore, we have nothing to request from them.
    41→    //
    42→    // ## The node is on a fork
    43→    //
    44→    // If a node is on a fork that has a lower finalized epoch, switching to that fork would
    45→    // cause us to revert a finalized block. This is not permitted, therefore we have no
    46→    // interest in their blocks.
    47→    //
    48→    // We keep these peers to allow them to sync from us.
    49→    return PeerSyncType.Behind;
    50→  }
    51→
    52→  if (remote.finalizedEpoch > local.finalizedEpoch) {
    53→    if (
    54→      // Peer is in next epoch, and head is within range => SYNCED
    55→      (local.finalizedEpoch + 1 === remote.finalizedEpoch &&
    56→        withinRangeOf(remote.headSlot, local.headSlot, slotImportTolerance)) ||
    57→      // Peer's head is known => SYNCED
    58→      forkChoice.hasBlock(remote.headRoot)
    59→    ) {
    60→      return PeerSyncType.FullySynced;
    61→    }
    62→    return PeerSyncType.Advanced;
    63→  }
    64→
    65→  // remote.finalizedEpoch == local.finalizedEpoch
    66→  // NOTE: if a peer has our same `finalizedEpoch` with a different `finalized_root`
    67→  // they are not considered relevant and won't be propagated to sync.
    68→  // Check if the peer is the peer is inside the tolerance range to be considered synced.
    69→  if (remote.headSlot < nearRangeStart) {
    70→    return PeerSyncType.Behind;
    71→  }
    72→
    73→  if (remote.headSlot > nearRangeEnd && !forkChoice.hasBlock(remote.headRoot)) {
    74→    // This peer has a head ahead enough of ours and we have no knowledge of their best block.
    75→    return PeerSyncType.Advanced;
    76→  }
    77→  // This peer is either in the tolerance range, or ahead us with an already rejected block.
    78→  return PeerSyncType.FullySynced;
    79→}
    80→
    81→export enum RangeSyncType {
    82→  /** A finalized chain sync should be started with this peer */
    83→  Finalized = "Finalized",
    84→  /** A head chain sync should be started with this peer */
    85→  Head = "Head",
    86→}
    87→
    88→// Cache Object.keys iteration for faster loops in metrics
    89→export const rangeSyncTypes = Object.keys(RangeSyncType) as RangeSyncType[];
    90→
    91→/**
    92→ * Check if a peer requires a finalized chain sync. Only if:
    93→ * - The remotes finalized epoch is greater than our current finalized epoch and we have
    94→ *   not seen the finalized hash before
    95→ */
    96→export function getRangeSyncType(local: Status, remote: Status, forkChoice: IForkChoice): RangeSyncType {
    97→  if (remote.finalizedEpoch > local.finalizedEpoch && !forkChoice.hasBlock(remote.finalizedRoot)) {
    98→    return RangeSyncType.Finalized;
    99→  }
   100→  return RangeSyncType.Head;
   101→}
   102→
   103→export function getRangeSyncTarget(
   104→  local: Status,
   105→  remote: Status,
   106→  forkChoice: IForkChoice
   107→): {syncType: RangeSyncType; startEpoch: Slot; target: ChainTarget} {
   108→  if (remote.finalizedEpoch > local.finalizedEpoch && !forkChoice.hasBlock(remote.finalizedRoot)) {
   109→    return {
   110→      // If  RangeSyncType.Finalized, the range of blocks fetchable from startEpoch and target must allow to switch
   111→      // to RangeSyncType.Head
   112→      //
   113→      // finalizedRoot is a block with slot <= computeStartSlotAtEpoch(finalizedEpoch).
   114→      // If finalizedEpoch does not start with a skipped slot, the SyncChain with this target MUST process the
   115→      // first block of the next epoch in order to trigger the condition above `forkChoice.hasBlock(remote.finalizedRoot)`
   116→      // and do a Head sync.
   117→      //
   118→      // When doing a finalized sync, we'll process blocks up to the finalized checkpoint, which does not allow to
   119→      // finalize that checkpoint. Instead, our head will be the finalized checkpoint and our finalized checkpoint will
   120→      // be some older checkpoint. After completing a finalized SyncChain:
   121→      //
   122→      // (== finalized, -- non-finalized)
   123→      // Remote  ====================================================|----------------|
   124→      // Local   =====================================|--------------|
   125→
   126→      syncType: RangeSyncType.Finalized,
   127→      startEpoch: local.finalizedEpoch,
   128→      target: {
   129→        slot: computeStartSlotAtEpoch(remote.finalizedEpoch),
   130→        root: remote.finalizedRoot,
   131→      },
   132→    };
   133→  }
   134→  return {
   135→    syncType: RangeSyncType.Head,
   136→    // The new peer has the same finalized (earlier filters should prevent a peer with an
   137→    // earlier finalized chain from reaching here).
   138→    startEpoch: Math.min(computeEpochAtSlot(local.headSlot), remote.finalizedEpoch),
