import {createBeaconConfig, createChainForkConfig, defaultChainConfig} from "@lodestar/config";
import {ForkName} from "@lodestar/params";
import {fulu, ssz} from "@lodestar/types";
import {describe, expect, it} from "vitest";

import {matchBlockWithDataColumns} from "./packages/beacon-node/src/network/reqresp/beaconBlocksMaybeBlobsByRange.js";
import {DataColumnsSource, BlockSource} from "./packages/beacon-node/src/chain/blocks/types.js";
import {INetwork} from "./packages/beacon-node/src/network/interface.js";
import {PeerAction} from "./packages/beacon-node/src/network/peers/score/interface.js";

describe("matchBlockWithDataColumns - head sync edge cases", () => {
  const chainConfig = createChainForkConfig({
    ...defaultChainConfig,
    ALTAIR_FORK_EPOCH: 0,
    BELLATRIX_FORK_EPOCH: 0,
    CAPELLA_FORK_EPOCH: 0,
    DENEB_FORK_EPOCH: 0,
    ELECTRA_FORK_EPOCH: 0,
    FULU_FORK_EPOCH: 0,
  });
  const genesisValidatorsRoot = Buffer.alloc(32, 0xaa);
  const config = createBeaconConfig(chainConfig, genesisValidatorsRoot);
  const peerId = "test-peer-id";
  const peerClient = "Prysm";

  it("should handle unmatched data columns in head sync (beyond endSlot)", () => {
    // Simulate the bug scenario:
    // 1. Initial download requested slots 27264-27295 (count=32)
    // 2. Peer returns blocks up to slot 27286
    // 3. Peer also returns data columns for slot 27287 (their current head)
    // 4. Since slot 27287 > endSlot (27295), this should NOT throw an error

    const startSlot = 27264;
    const count = 32;
    const endSlot = startSlot + count - 1; // 27295

    // Create blocks for slots 27264-27286 (19 blocks)
    const blocks = [];
    for (let slot = 27264; slot <= 27286; slot++) {
      const block = ssz.fulu.SignedBeaconBlock.defaultValue();
      block.message.slot = slot;
      // Add some blob commitments
      block.message.body.blobKzgCommitments.push(ssz.deneb.KZGCommitment.defaultValue());
      blocks.push({data: block});
    }

    // Create data columns for slots 27264-27287 (includes extra slot 27287)
    const dataColumnSidecars: fulu.DataColumnSidecar[] = [];
    const columnIndexes = [50, 69, 81, 85, 94, 124]; // 6 custody columns

    for (let slot = 27264; slot <= 27287; slot++) {
      for (const colIndex of columnIndexes) {
        const dataColumn = ssz.fulu.DataColumnSidecar.defaultValue();
        dataColumn.signedBlockHeader.message.slot = slot;
        dataColumn.index = colIndex;
        dataColumnSidecars.push(dataColumn);
      }
    }

    const sampledColumns = columnIndexes;
    const requestedColumns = columnIndexes;

    let peerReported = false;
    const mockNetwork = {
      reportPeer: (peer: string, action: PeerAction, reason: string) => {
        peerReported = true;
      }
    } as Partial<INetwork> as INetwork;

    // This should throw "Unmatched dataColumnSidecars" error in the current implementation
    // because slot 27287 <= endSlot check will be true (27287 <= 27295)
    expect(() => {
      matchBlockWithDataColumns(
        mockNetwork,
        peerId,
        config,
        sampledColumns,
        requestedColumns,
        blocks,
        dataColumnSidecars,
        endSlot,
        BlockSource.byRange,
        DataColumnsSource.byRange,
        null, // no partial download
        peerClient,
        null, // no metrics
        undefined // no logger
      );
    }).toThrow("Unmatched dataColumnSidecars");

    expect(peerReported).toBe(true);
  });

  it("should match data columns correctly when slots match but block roots differ", () => {
    // This test verifies the need for block root comparison
    // In head sync, different peers may have different blocks at the same slot (different forks)

    const startSlot = 100;
    const count = 2;
    const endSlot = startSlot + count - 1; // 101

    // Create block for slot 100 with specific root
    const block1 = ssz.fulu.SignedBeaconBlock.defaultValue();
    block1.message.slot = 100;
    block1.message.body.blobKzgCommitments.push(ssz.deneb.KZGCommitment.defaultValue());

    // Data column for slot 100 but with different block root (from different fork)
    const dataColumn = ssz.fulu.DataColumnSidecar.defaultValue();
    dataColumn.signedBlockHeader.message.slot = 100;
    dataColumn.index = 50;

    // In current implementation, this would match by slot alone
    // But it should also verify the block root matches
    const sampledColumns = [50];
    const requestedColumns = [50];

    const mockNetwork = {
      reportPeer: (peer: string, action: PeerAction, reason: string) => {}
    } as Partial<INetwork> as INetwork;

    // Currently this succeeds because it only checks slot
    // After fix, it should also check block root
    const result = matchBlockWithDataColumns(
      mockNetwork,
      peerId,
      config,
      sampledColumns,
      requestedColumns,
      [{data: block1}],
      [dataColumn],
      endSlot,
      BlockSource.byRange,
      DataColumnsSource.byRange,
      null,
      peerClient,
      null,
      undefined
    );

    expect(result).toBeDefined();
    expect(result.length).toBe(1);
  });
});

