      blocks,
      dataColumnSidecars,
      endSlot,
      BlockSource.byRange,
      DataColumnsSource.byRange,
      null,
      peerClient,
      null,
      undefined
    );

    expect(result).toBeDefined();
    expect(result.length).toBe(2);
  });
