    const forkSeq = config.getForkSeq(block.data.message.slot);
    if (forkSeq < ForkSeq.fulu) {
      throw Error(`Invalid block forkSeq=${forkSeq} < ForSeq.fulu for matchBlockWithDataColumns`);
    }
