// If there are still unconsumed data columns, check if they are truly problematic
// During head sync, peers may return data columns for their current head which is ahead of our request
// or for blocks at the same slot but on a different fork (which we filtered out by block root matching above)
// We should only report an error if the unconsumed data columns are for slots we requested blocks for
// but couldn't match due to missing blocks (not due to fork differences)
if (allDataColumnSidecars[dataColumnSideCarIndex] !== undefined) {
  const firstUnmatchedSlot = allDataColumnSidecars[dataColumnSideCarIndex].signedBlockHeader.message.slot;

  // If unconsumed data columns are within the requested range AND before or at the last matched slot,
  // this indicates a real mismatch problem (missing blocks or incorrect peer response)
  // If they are beyond the last matched slot, they might be from the peer's more recent head
  // which is acceptable during head sync
  if (firstUnmatchedSlot <= endSlot && firstUnmatchedSlot <= lastMatchedSlot) {
    network.reportPeer(peerId, PeerAction.LowToleranceError, "Unmatched dataColumnSidecars");
    throw Error(
      `Unmatched dataColumnSidecars, blocks=${allBlocks.length}, blobs=${
        allDataColumnSidecars.length
      } lastMatchedSlot=${lastMatchedSlot}, pending dataColumnSidecars slots=${allDataColumnSidecars
        .slice(dataColumnSideCarIndex)
        .map((blb) => blb.signedBlockHeader.message.slot)
        .join(" ")}`
    );
  } else {
    // Log a debug message for unconsumed data columns that are ahead of our last matched slot
    // This is expected during head sync when the peer is more up-to-date
    logger?.debug("Ignoring unconsumed dataColumnSidecars ahead of matched blocks", {
      firstUnmatchedSlot,
      lastMatchedSlot,
      endSlot,
      unmatchedCount: allDataColumnSidecars.length - dataColumnSideCarIndex,
      peerClient,
    });
  }
}

