// Simple test to verify the fix logic
// Simulates the scenario from the bug report

console.log("Testing fix for head sync unmatched data columns issue...\n");

// Scenario from bug report:
// Request: slots 27264-27295 (count=32, endSlot=27295)
// Blocks returned: 27264-27286 (lastMatchedSlot=27286)
// Data columns: includes slot 27287 (peer's current head)

const lastMatchedSlot = 27286;
const endSlot = 27295;
const unmatchedDataColumnSlot = 27287;

console.log("Test Case 1: Unmatched data column beyond lastMatchedSlot (should NOT throw)");
console.log(`  lastMatchedSlot: ${lastMatchedSlot}`);
console.log(`  endSlot: ${endSlot}`);
console.log(`  unmatchedDataColumnSlot: ${unmatchedDataColumnSlot}`);

// Old logic (buggy):
// if (unmatchedDataColumnSlot <= endSlot)  // 27287 <= 27295 = true -> THROWS ERROR

// New logic (fixed):
// if (unmatchedDataColumnSlot <= endSlot && unmatchedDataColumnSlot <= lastMatchedSlot)
const shouldThrowOld = unmatchedDataColumnSlot <= endSlot;
const shouldThrowNew = unmatchedDataColumnSlot <= endSlot && unmatchedDataColumnSlot <= lastMatchedSlot;

console.log(`  Old logic would throw: ${shouldThrowOld}`);
console.log(`  New logic would throw: ${shouldThrowNew}`);
console.log(`  Expected: false (should NOT throw)\n`);

if (!shouldThrowNew && shouldThrowOld) {
  console.log("✓ Test Case 1 PASSED: Fix correctly prevents throwing error\n");
} else {
  console.log("✗ Test Case 1 FAILED\n");
}

// Test Case 2: Truly unmatched data column (should throw)
console.log("Test Case 2: Unmatched data column at or before lastMatchedSlot (should throw)");
const lastMatchedSlot2 = 27286;
const endSlot2 = 27295;
const unmatchedDataColumnSlot2 = 27280; // Before lastMatchedSlot, indicating missing block

console.log(`  lastMatchedSlot: ${lastMatchedSlot2}`);
console.log(`  endSlot: ${endSlot2}`);
console.log(`  unmatchedDataColumnSlot: ${unmatchedDataColumnSlot2}`);

const shouldThrowOld2 = unmatchedDataColumnSlot2 <= endSlot2;
const shouldThrowNew2 = unmatchedDataColumnSlot2 <= endSlot2 && unmatchedDataColumnSlot2 <= lastMatchedSlot2;

console.log(`  Old logic would throw: ${shouldThrowOld2}`);
console.log(`  New logic would throw: ${shouldThrowNew2}`);
console.log(`  Expected: true (should throw)\n`);

if (shouldThrowNew2 && shouldThrowOld2) {
  console.log("✓ Test Case 2 PASSED: Fix correctly throws error for genuine mismatch\n");
} else {
  console.log("✗ Test Case 2 FAILED\n");
}

// Test Case 3: Data column beyond endSlot (should not throw)
console.log("Test Case 3: Data column beyond endSlot (should NOT throw)");
