import {createBeaconConfig, createChainForkConfig, defaultChainConfig} from "@lodestar/config";
import {fulu, ssz} from "@lodestar/types";
import {describe, expect, it, vi} from "vitest";

import {matchBlockWithDataColumns, matchBlockWithBlobs} from "../../../src/network/reqresp/beaconBlocksMaybeBlobsByRange.js";
import {DataColumnsSource, BlockSource} from "../../../src/chain/blocks/types.js";
import {INetwork} from "../../../src/network/interface.js";
import {PeerAction} from "../../../src/network/peers/score/interface.js";

describe("matchBlockWithDataColumns - head sync fixes", () => {
  const chainConfig = createChainForkConfig({
    ...defaultChainConfig,
    ALTAIR_FORK_EPOCH: 0,
    BELLATRIX_FORK_EPOCH: 0,
    CAPELLA_FORK_EPOCH: 0,
    DENEB_FORK_EPOCH: 0,
    ELECTRA_FORK_EPOCH: 0,
    FULU_FORK_EPOCH: 0,
  });
  const genesisValidatorsRoot = Buffer.alloc(32, 0xaa);
  const config = createBeaconConfig(chainConfig, genesisValidatorsRoot);
  const peerId = "test-peer-id";
  const peerClient = "Prysm";

  it("should NOT throw error for unmatched data columns beyond lastMatchedSlot (head sync scenario)", () => {
    // Simulate the bug scenario from the issue:
    // Request: slots 100-131 (count=32, endSlot=131)
    // Blocks returned: 100-110 (lastMatchedSlot=110)
    // Data columns: includes slot 111 (peer's current head, more recent than our request)
    // This should NOT throw an error as the unmatched slot (111) is beyond lastMatchedSlot (110)

    const startSlot = 100;
    const count = 32;
    const endSlot = startSlot + count - 1; // 131

    // Create blocks for slots 100-110
    const blocks = [];
    for (let slot = 100; slot <= 110; slot++) {
      const block = ssz.fulu.SignedBeaconBlock.defaultValue();
      block.message.slot = slot;
      block.message.body.blobKzgCommitments.push(ssz.deneb.KZGCommitment.defaultValue());
      blocks.push({data: block});
    }

    // Create data columns for slots 100-111 (includes extra slot 111 from peer's head)
    const dataColumnSidecars: fulu.DataColumnSidecar[] = [];
    const columnIndexes = [50, 69];

    for (let slot = 100; slot <= 111; slot++) {
      for (const colIndex of columnIndexes) {
        const dataColumn = ssz.fulu.DataColumnSidecar.defaultValue();
        const block = blocks.find((b) => b.data.message.slot === slot);

        dataColumn.signedBlockHeader.message.slot = slot;
        if (block) {
          // Use the actual block's header for proper root matching
          const blockRoot = config.getForkTypes(slot).BeaconBlock.hashTreeRoot(block.data.message);
          dataColumn.signedBlockHeader.message.parentRoot = block.data.message.parentRoot;
          dataColumn.signedBlockHeader.message.stateRoot = block.data.message.stateRoot;
          dataColumn.signedBlockHeader.message.bodyRoot = blockRoot;
        }
        dataColumn.index = colIndex;
        dataColumnSidecars.push(dataColumn);
      }
    }

    const sampledColumns = columnIndexes;
    const requestedColumns = columnIndexes;

    const reportPeerMock = vi.fn();
    const mockNetwork = {
      reportPeer: reportPeerMock
    } as Partial<INetwork> as INetwork;

    // This should NOT throw because slot 111 > lastMatchedSlot (110)
    const result = matchBlockWithDataColumns(
      mockNetwork,
      peerId,
      config,
      sampledColumns,
      requestedColumns,
      blocks,
      dataColumnSidecars,
      endSlot,
      BlockSource.byRange,
      DataColumnsSource.byRange,
      null,
      peerClient,
      null,
      undefined
    );

    expect(result).toBeDefined();
    expect(result.length).toBe(11); // All 11 blocks should be matched
    expect(reportPeerMock).not.toHaveBeenCalled(); // Peer should not be reported
  });

  it("should throw error for truly unmatched data columns at or before lastMatchedSlot", () => {
    // Test that genuine mismatches (missing blocks) still throw errors
    // Blocks: 100, 102, 103 (slot 101 is missing)
    // Data columns: 100, 101, 102, 103
    // This SHOULD throw because slot 101 data columns have no matching block
    // and 101 <= lastMatchedSlot (103)

    const endSlot = 110;

    // Create blocks for slots 100, 102, 103 (skip 101)
    const blocks = [];
    for (const slot of [100, 102, 103]) {
      const block = ssz.fulu.SignedBeaconBlock.defaultValue();
      block.message.slot = slot;
      block.message.body.blobKzgCommitments.push(ssz.deneb.KZGCommitment.defaultValue());
      blocks.push({data: block});
    }

    // Create data columns for all slots 100-103 (including missing 101)
    const dataColumnSidecars: fulu.DataColumnSidecar[] = [];
    const columnIndexes = [50];

    for (let slot = 100; slot <= 103; slot++) {
      for (const colIndex of columnIndexes) {
        const dataColumn = ssz.fulu.DataColumnSidecar.defaultValue();
        const block = blocks.find((b) => b.data.message.slot === slot);

        dataColumn.signedBlockHeader.message.slot = slot;
        if (block) {
          const blockRoot = config.getForkTypes(slot).BeaconBlock.hashTreeRoot(block.data.message);
          dataColumn.signedBlockHeader.message.parentRoot = block.data.message.parentRoot;
          dataColumn.signedBlockHeader.message.stateRoot = block.data.message.stateRoot;
          dataColumn.signedBlockHeader.message.bodyRoot = blockRoot;
        }
        dataColumn.index = colIndex;
        dataColumnSidecars.push(dataColumn);
      }
    }

    const sampledColumns = columnIndexes;
    const requestedColumns = columnIndexes;

    const reportPeerMock = vi.fn();
    const mockNetwork = {
      reportPeer: reportPeerMock
    } as Partial<INetwork> as INetwork;

    // This SHOULD throw because slot 101 data columns are unmatched
    // and 101 <= endSlot (110) and 101 <= lastMatchedSlot (100, first matched)
    // Actually after matching slot 100, the next unmatched is 101, but lastMatchedSlot would be 100
    // After matching 102 and 103, lastMatchedSlot would be 103
    // And slot 101 (unmatched) <= lastMatchedSlot (103), so it should throw

    // Wait, the logic is: firstUnmatchedSlot <= lastMatchedSlot
