    const result = matchBlockWithDataColumns(
      mockNetwork,
      peerId,
      config,
      sampledColumns,
      requestedColumns,
      blocks,
      dataColumnSidecars,
      endSlot,
      BlockSource.byRange,
      DataColumnsSource.byRange,
      null,
      peerClient,
      null,
      undefined
    );

    expect(result).toBeDefined();
    expect(result.length).toBe(11); // All 11 blocks should be matched
    expect(reportPeerMock).not.toHaveBeenCalled(); // Peer should not be reported
  });

