    logger?.debug("Skipping data column with mismatched block root", {
      blockSlot: block.data.message.slot,
      dataColumnSlot: dataColumn.signedBlockHeader.message.slot,
      dataColumnIndex: dataColumn.index,
      peerClient,
    });
