    peerId,
    config,
    sampledColumns,
    requestedColumns,
    blocks,
    dataColumnSidecars,
    endSlot,
    BlockSource.byRange,
    DataColumnsSource.byRange,
    null,
    peerClient,
    null,
    undefined
  );

  expect(result).toBeDefined();
