    const columnIndexes = [50];

    for (let slot = 100; slot <= 105; slot++) {
      for (const colIndex of columnIndexes) {
        const dataColumn = ssz.fulu.DataColumnSidecar.defaultValue();
        const block = blocks.find((b) => b.data.message.slot === slot);

        dataColumn.signedBlockHeader.message.slot = slot;
        if (block) {
